 [NSHTTPCookie]

            var cookieProperties = [String: AnyObject]()
            for cookie in allCookies {
                cookieProperties[NSHTTPCookieName] = cookie.name
                cookieProperties[NSHTTPCookieValue] = cookie.value
                println("name: \(cookie.name) value: \(cookie.value)")
